 1→import type { RecordId } from "surrealdb";
 2→import type { BrainAction } from "../oauth/types";
 3→
 4→// --- Intent Status (state machine states) ---
 5→
 6→export type IntentStatus =
 7→  | "draft"
 8→  | "pending_auth"
 9→  | "pending_veto"
10→  | "authorized"
11→  | "executing"
12→  | "completed"
13→  | "vetoed"
14→  | "failed";
15→
16→// --- Action Specification ---
17→
18→export type ActionSpec = {
19→  provider: string;
20→  action: string;
21→  params?: Record<string, unknown>;
22→};
23→
24→// --- Budget Limit ---
25→
26→export type BudgetLimit = {
27→  amount: number;
28→  currency: string;
29→};
30→
31→// --- Evaluation Result ---
32→
33→export type EvaluationResult = {
34→  decision: "APPROVE" | "REJECT";
35→  risk_score: number;
36→  reason: string;
37→};
38→
39→// --- Routing Decision (discriminated union) ---
40→
41→export type RoutingDecision =
42→  | { route: "auto_approve" }
43→  | { route: "veto_window"; expires_at: Date }
44→  | { route: "reject"; reason: string };
45→
46→// --- Intent Record ---
47→
48→export type IntentRecord = {
49→  id: RecordId<"intent", string>;
50→  goal: string;
51→  reasoning: string;
52→  status: IntentStatus;
53→  priority: number;
54→  action_spec: ActionSpec;
55→  budget_limit?: BudgetLimit;
56→  evaluation?: EvaluationResult & {
57→    evaluated_at: Date;
58→    policy_only: boolean;
59→  };
60→  veto_expires_at?: Date;
61→  veto_reason?: string;
62→  error_reason?: string;
63→  authorization_details?: BrainAction[];
64→  dpop_jwk_thumbprint?: string;
65→  token_issued_at?: Date;
66→  token_expires_at?: Date;
67→  trace_id: RecordId<"trace", string>;
68→  requester: RecordId<"identity", string>;
69→  workspace: RecordId<"workspace", string>;
70→  created_at: Date;
71→  updated_at?: Date;
72→  expiry?: Date;
73→};
