  1→import { RecordId } from "surrealdb";
  2→import { jsonError, jsonResponse } from "../http/response";
  3→import { logError, logInfo } from "../http/observability";
  4→import { updateIntentStatus, listPendingIntents, getIntentById } from "./intent-queries";
  5→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  6→import { routeByRisk } from "./risk-router";
  7→import { renderConsentDisplay, validateTighterBounds } from "../oauth/consent-renderer";
  8→import type { ServerDependencies } from "../runtime/types";
  9→import type { IntentRecord } from "./types";
 10→import type { BrainAction } from "../oauth/types";
 11→
 12→// --- Route Handler Types ---
 13→
 14→type IntentRouteHandlers = {
 15→  handleEvaluate: (intentId: string, request: Request) => Promise<Response>;
 16→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 17→  handleListPending: (workspaceId: string) => Promise<Response>;
 18→  handleConsent: (workspaceId: string, intentId: string) => Promise<Response>;
 19→  handleApprove: (workspaceId: string, intentId: string) => Promise<Response>;
 20→  handleConstrain: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 21→};
 22→
 23→// --- Factory ---
 24→
 25→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 26→  const { surreal } = deps;
 27→
 28→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
 29→
 30→  const handleEvaluate = async (intentId: string, request: Request): Promise<Response> => {
 31→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 32→    let body: IntentRecord | undefined;
 33→    try {
 34→      body = await request.json() as IntentRecord;
 35→    } catch {
 36→      body = undefined;
 37→    }
 38→
 39→    const bodyIntentId = body && typeof body.id === "object" && body.id !== undefined
 40→      ? (body.id.id as string)
 41→      : undefined;
 42→
 43→    if (bodyIntentId && bodyIntentId !== intentId) {
 44→      return jsonError("Intent ID mismatch between path and payload", 400);
 45→    }
 46→
 47→    if (!body) {
 48→      return jsonError("Invalid JSON body", 400);
 49→    }
 50→
 51→    if (!body.requester) {
 52→      return jsonError("Missing requester in intent body", 400);
 53→    }
 54→
 55→    logInfo("intent.evaluate.received", "Evaluate endpoint received intent", {
 56→      intentId,
 57→      status: body.status,
 58→      goal: body.goal,
 59→    });
 60→
 61→    // Idempotency guard: only process intents in pending_auth status
 62→    if (body.status !== "pending_auth") {
 63→      logInfo("intent.evaluate.skipped", "Intent not in pending_auth status", {
 64→        intentId,
 65→        currentStatus: body.status,
 66→      });
 67→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
 68→    }
 69→
 70→    try {
 71→      // Pipeline: policy gate -> LLM evaluator -> risk router -> status update
 72→      const requesterId = typeof body.requester === "object" && body.requester !== undefined
 73→        ? (body.requester.id as string)
 74→        : String(body.requester);
 75→
 76→      const evaluation = await evaluateIntent({
 77→        intent: {
 78→          goal: body.goal,
 79→          reasoning: body.reasoning,
 80→          action_spec: body.action_spec,
 81→          budget_limit: body.budget_limit,
 82→          requester: requesterId,
 83→        },
 84→        policy: {},
 85→        llmEvaluator,
 86→      });
 87→
 88→      const routing = routeByRisk(evaluation);
 89→      const evaluationRecord = {
 90→        ...evaluation,
 91→        evaluated_at: new Date(),
 92→      };
 93→
 94→      switch (routing.route) {
 95→        case "auto_approve": {
 96→          const result = await updateIntentStatus(surreal, intentId, "authorized", {
 97→            evaluation: evaluationRecord,
 98→          });
 99→          if (!result.ok) {
100→            logError(
101→              "intent.evaluate.update_failed",
102→              "Failed to update intent status to authorized",
103→              new Error(result.error),
104→              { intentId },
105→            );
106→            return jsonError(result.error, 409);
107→          }
108→          logInfo("intent.authorized", "Intent auto-approved", { intentId });
109→          return jsonResponse({ intentId, status: "authorized", evaluation }, 200);
110→        }
111→
112→        case "veto_window": {
113→          const result = await updateIntentStatus(surreal, intentId, "pending_veto", {
114→            evaluation: evaluationRecord,
115→            veto_expires_at: routing.expires_at,
116→          });
117→          if (!result.ok) {
118→            logError(
119→              "intent.evaluate.update_failed",
120→              "Failed to update intent status to pending_veto",
121→              new Error(result.error),
122→              { intentId },
123→            );
124→            return jsonError(result.error, 409);
125→          }
126→          logInfo("intent.pending_veto", "Intent requires veto window", {
127→            intentId,
128→            veto_expires_at: routing.expires_at.toISOString(),
129→          });
130→          return jsonResponse({
131→            intentId,
132→            status: "pending_veto",
133→            evaluation,
134→            veto_expires_at: routing.expires_at.toISOString(),
135→          }, 200);
136→        }
137→
138→        case "reject": {
139→          const result = await updateIntentStatus(surreal, intentId, "vetoed", {
140→            evaluation: evaluationRecord,
141→          });
142→          if (!result.ok) {
143→            logError(
144→              "intent.evaluate.update_failed",
145→              "Failed to update intent status to vetoed",
146→              new Error(result.error),
147→              { intentId },
148→            );
149→            return jsonError(result.error, 409);
150→          }
151→          logInfo("intent.vetoed", "Intent rejected by evaluation", {
152→            intentId,
153→            reason: routing.reason,
154→          });
155→          return jsonResponse({ intentId, status: "vetoed", evaluation }, 200);
156→        }
157→      }
158→    } catch (error) {
159→      logError("intent.evaluate.error", "Intent evaluation pipeline failed", error, {
160→        intentId,
161→      });
162→      return jsonError("Internal evaluation error", 500);
163→    }
164→  };
165→
166→  const handleVeto = async (
167→    workspaceId: string,
168→    intentId: string,
169→    request: Request,
170→  ): Promise<Response> => {
171→    let body: { reason: string };
172→    try {
173→      body = await request.json() as { reason: string };
174→    } catch {
175→      return jsonError("Invalid JSON body", 400);
176→    }
177→
178→    if (!body.reason || typeof body.reason !== "string" || body.reason.trim().length === 0) {
179→      return jsonError("reason is required", 400);
180→    }
181→
182→    const result = await updateIntentStatus(surreal, intentId, "vetoed", {
183→      veto_reason: body.reason.trim(),
184→    });
185→
186→    if (!result.ok) {
187→      logError("intent.veto.failed", "Failed to veto intent", new Error(result.error), {
188→        intentId,
189→        workspaceId,
190→      });
191→      return jsonError(result.error, 409);
192→    }
193→
194→    logInfo("intent.vetoed", "Intent vetoed by user", {
195→      intentId,
196→      workspaceId,
197→      reason: body.reason.trim(),
198→    });
199→
200→    return jsonResponse({
201→      intentId,
202→      status: "vetoed",
203→    }, 200);
204→  };
205→
206→  const handleListPending = async (workspaceId: string): Promise<Response> => {
207→    const intents = await listPendingIntents(surreal, workspaceId);
208→
209→    return jsonResponse({
210→      intents: intents.map((intent) => ({
211→        id: intent.id.id as string,
212→        goal: intent.goal,
213→        reasoning: intent.reasoning,
214→        priority: intent.priority,
215→        action_spec: intent.action_spec,
216→        veto_expires_at: intent.veto_expires_at,
217→        created_at: intent.created_at,
218→      })),
219→    }, 200);
220→  };
221→
222→  const handleConsent = async (
223→    _workspaceId: string,
224→    intentId: string,
225→  ): Promise<Response> => {
226→    const intent = await getIntentById(surreal, intentId);
227→    if (!intent) {
228→      return jsonError("Intent not found", 404);
229→    }
230→
231→    // Only pending_veto intents have consent display
232→    if (intent.status !== "pending_veto") {
233→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
234→    }
235→
236→    const authDetails = intent.authorization_details ?? [];
237→    const firstAction = authDetails[0];
238→
239→    const consentDisplay = firstAction
240→      ? renderConsentDisplay(firstAction)
241→      : { action_display: "Unknown", resource_display: "Unknown" };
242→
243→    return jsonResponse({
244→      ...consentDisplay,
245→      risk_score: intent.evaluation?.risk_score ?? 0,
246→      reasoning: intent.evaluation?.reason ?? "",
247→      expires_at: intent.veto_expires_at
248→        ? (intent.veto_expires_at instanceof Date
249→          ? intent.veto_expires_at.toISOString()
250→          : String(intent.veto_expires_at))
251→        : "",
252→    }, 200);
253→  };
254→
255→  const handleApprove = async (
256→    workspaceId: string,
257→    intentId: string,
258→  ): Promise<Response> => {
259→    const result = await updateIntentStatus(surreal, intentId, "authorized");
260→
261→    if (!result.ok) {
262→      logError("intent.approve.failed", "Failed to approve intent", new Error(result.error), {
263→        intentId,
264→        workspaceId,
265→      });
266→      return jsonError(result.error, 409);
267→    }
268→
269→    logInfo("intent.approved", "Intent approved by human", {
270→      intentId,
271→      workspaceId,
272→    });
273→
274→    return jsonResponse({
275→      intentId,
276→      status: "authorized",
277→    }, 200);
278→  };
279→
280→  const handleConstrain = async (
281→    workspaceId: string,
282→    intentId: string,
283→    request: Request,
284→  ): Promise<Response> => {
285→    let body: { constrained_authorization_details: BrainAction[] };
286→    try {
287→      body = await request.json() as { constrained_authorization_details: BrainAction[] };
288→    } catch {
289→      return jsonError("Invalid JSON body", 400);
290→    }
291→
292→    if (!body.constrained_authorization_details || !Array.isArray(body.constrained_authorization_details)) {
293→      return jsonError("constrained_authorization_details is required", 400);
294→    }
295→
296→    const intent = await getIntentById(surreal, intentId);
297→    if (!intent) {
298→      return jsonError("Intent not found", 404);
299→    }
300→
301→    if (intent.status !== "pending_veto") {
302→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
303→    }
304→
305→    const originalDetails = intent.authorization_details ?? [];
306→    const proposedDetails = body.constrained_authorization_details;
307→
308→    // Validate each proposed action against its original
309→    for (let i = 0; i < proposedDetails.length; i++) {
310→      const original = originalDetails[i];
311→      const proposed = proposedDetails[i];
312→
313→      if (!original) {
314→        return jsonError(`No original authorization_details at index ${i}`, 400);
315→      }
316→
317→      const boundsCheck = validateTighterBounds(original, proposed);
318→      if (!boundsCheck.valid) {
319→        return jsonError(
320→          `Constraint validation failed: ${boundsCheck.violations.join("; ")}`,
321→          400,
322→        );
323→      }
324→    }
325→
326→    // Update intent with tighter constraints and authorize
327→    const record = await updateIntentStatus(surreal, intentId, "authorized", {});
328→    if (!record.ok) {
329→      return jsonError(record.error, 409);
330→    }
331→
332→    // Update the authorization_details with the constrained version
333→    await surreal.query(
334→      "UPDATE $record SET authorization_details = $details;",
335→      {
336→        record: new RecordId("intent", intentId),
337→        details: proposedDetails,
338→      },
339→    );
340→
341→    logInfo("intent.constrained", "Intent constrained and authorized by human", {
342→      intentId,
343→      workspaceId,
344→    });
345→
346→    return jsonResponse({
347→      intentId,
348→      status: "authorized",
349→    }, 200);
350→  };
351→
352→  return { handleEvaluate, handleVeto, handleListPending, handleConsent, handleApprove, handleConstrain };
353→}
