 1→import type { IntentStatus } from "./types";
 2→
 3→// --- Transition Result (railway-oriented) ---
 4→
 5→export type TransitionResult =
 6→  | { ok: true; status: IntentStatus }
 7→  | { ok: false; error: string };
 8→
 9→// --- Legal Transition Map ---
10→// Each key maps to the set of statuses reachable from that state.
11→
12→const TRANSITION_MAP: Record<IntentStatus, ReadonlyArray<IntentStatus>> = {
13→  draft: ["pending_auth"],
14→  pending_auth: ["pending_veto", "authorized", "vetoed", "failed"],
15→  pending_veto: ["authorized", "vetoed"],
16→  authorized: ["executing"],
17→  executing: ["completed", "failed"],
18→  completed: [],
19→  vetoed: [],
20→  failed: [],
21→};
22→
23→// --- Pure transition function ---
24→
25→export const transitionStatus = (
26→  from: IntentStatus,
27→  to: IntentStatus,
28→): TransitionResult => {
29→  const allowedTargets = TRANSITION_MAP[from];
30→
31→  if (allowedTargets.includes(to)) {
32→    return { ok: true, status: to };
33→  }
34→
35→  return {
36→    ok: false,
37→    error: `Invalid transition from "${from}" to "${to}"`,
38→  };
39→};
