127→export async function updateIntentStatus(
128→  surreal: Surreal,
129→  intentId: string,
130→  newStatus: IntentStatus,
131→  updates?: StatusUpdateFields,
132→): Promise<{ ok: true; record: IntentRecord } | { ok: false; error: string }> {
133→  const existing = await getIntentById(surreal, intentId);
134→  if (!existing) {
135→    return { ok: false, error: `Intent ${intentId} not found` };
136→  }
137→
138→  const transition = transitionStatus(existing.status, newStatus);
139→  if (!transition.ok) {
140→    return { ok: false, error: transition.error };
141→  }
142→
143→  const record = new RecordId("intent", intentId);
144→  const now = new Date();
145→
146→  const setFields: Record<string, unknown> = {
147→    status: newStatus,
148→    updated_at: now,
149→  };
150→
151→  if (updates?.evaluation) {
152→    setFields.evaluation = updates.evaluation;
153→  }
154→  if (updates?.veto_expires_at) {
155→    setFields.veto_expires_at = updates.veto_expires_at;
156→  }
157→  if (updates?.veto_reason) {
158→    setFields.veto_reason = updates.veto_reason;
159→  }
160→  if (updates?.error_reason) {
161→    setFields.error_reason = updates.error_reason;
162→  }
163→
164→  const [rows] = await surreal.query<[IntentRecord[]]>(
165→    "UPDATE $record MERGE $fields RETURN AFTER;",
166→    {
167→      record,
168→      fields: setFields,
169→    },
170→  );
171→
172→  return { ok: true, record: rows[0] };
173→}
