  1→/**
  2→ * Consent Renderer -- pure functions for human-readable authorization display.
  3→ *
  4→ * Transforms brain_action authorization_details into display labels,
  5→ * formats provider-specific values, and validates tighter-bounds constraints.
  6→ *
  7→ * Pure domain logic -- no IO imports.
  8→ */
  9→import type { BrainAction } from "./types";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Display types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type ConsentDisplay = {
 16→  action_display: string;
 17→  resource_display: string;
 18→  constraints_display?: Record<string, string>;
 19→};
 20→
 21→export type BoundsValidationResult =
 22→  | { valid: true }
 23→  | { valid: false; violations: string[] };
 24→
 25→// ---------------------------------------------------------------------------
 26→// Action verb rendering
 27→// ---------------------------------------------------------------------------
 28→
 29→const ACTION_LABELS: Record<string, string> = {
 30→  read: "Read",
 31→  write: "Write",
 32→  create: "Create",
 33→  update: "Update",
 34→  delete: "Delete",
 35→  execute: "Execute",
 36→  admin: "Administer",
 37→};
 38→
 39→export function renderActionLabel(action: string): string {
 40→  return ACTION_LABELS[action] ?? capitalize(action);
 41→}
 42→
 43→// ---------------------------------------------------------------------------
 44→// Resource type rendering
 45→// ---------------------------------------------------------------------------
 46→
 47→const RESOURCE_LABELS: Record<string, string> = {
 48→  workspace: "Workspace",
 49→  task: "Task",
 50→  decision: "Decision",
 51→  invoice: "Invoice",
 52→  feature: "Feature",
 53→  project: "Project",
 54→  observation: "Observation",
 55→};
 56→
 57→export function renderResourceLabel(resource: string): string {
 58→  return RESOURCE_LABELS[resource] ?? capitalize(resource);
 59→}
 60→
 61→// ---------------------------------------------------------------------------
 62→// Constraint value formatting
 63→// ---------------------------------------------------------------------------
 64→
 65→const AMOUNT_FIELDS = new Set(["amount", "max_amount", "min_amount", "budget"]);
 66→
 67→export function renderConstraintValue(key: string, value: unknown): string {
 68→  if (AMOUNT_FIELDS.has(key) && typeof value === "number") {
 69→    return formatCentsToDollars(value);
 70→  }
 71→  return String(value);
 72→}
 73→
 74→function formatCentsToDollars(cents: number): string {
 75→  const dollars = cents / 100;
 76→  return `$${dollars.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
 77→}
 78→
 79→// ---------------------------------------------------------------------------
 80→// Full consent display rendering
 81→// ---------------------------------------------------------------------------
 82→
 83→export function renderConsentDisplay(action: BrainAction): ConsentDisplay {
 84→  const display: ConsentDisplay = {
 85→    action_display: renderActionLabel(action.action),
 86→    resource_display: renderResourceLabel(action.resource),
 87→  };
 88→
 89→  if (action.constraints && Object.keys(action.constraints).length > 0) {
 90→    display.constraints_display = Object.fromEntries(
 91→      Object.entries(action.constraints).map(([key, value]) => [
 92→        key,
 93→        renderConstraintValue(key, value),
 94→      ]),
 95→    );
 96→  }
 97→
 98→  return display;
 99→}
