101→// ---------------------------------------------------------------------------
102→// Tighter-bounds constraint validation
103→// ---------------------------------------------------------------------------
104→
105→export function validateTighterBounds(
106→  original: BrainAction,
107→  proposed: BrainAction,
108→): BoundsValidationResult {
109→  const violations: string[] = [];
110→
111→  // Action and resource must match exactly
112→  if (original.action !== proposed.action) {
113→    violations.push(
114→      `Action mismatch: cannot change '${original.action}' to '${proposed.action}'`,
115→    );
116→  }
117→  if (original.resource !== proposed.resource) {
118→    violations.push(
119→      `Resource mismatch: cannot change '${original.resource}' to '${proposed.resource}'`,
120→    );
121→  }
122→
123→  if (violations.length > 0) {
124→    return { valid: false, violations };
125→  }
126→
127→  // If original has constraints, proposed must not drop them
128→  if (original.constraints) {
129→    if (!proposed.constraints) {
130→      violations.push("Cannot remove existing constraints (scope widening)");
131→      return { valid: false, violations };
132→    }
133→
134→    // Each original constraint must be present and <= in proposed
135→    for (const [key, originalValue] of Object.entries(original.constraints)) {
136→      const proposedValue = proposed.constraints[key];
137→
138→      if (proposedValue === undefined) {
139→        violations.push(`Missing constraint '${key}' from proposed (scope widening)`);
140→        continue;
141→      }
142→
143→      if (typeof originalValue === "number" && typeof proposedValue === "number") {
144→        if (proposedValue > originalValue) {
145→          violations.push(
146→            `${key}: ${proposedValue} exceeds original bound of ${originalValue}`,
147→          );
148→        }
149→      } else if (typeof originalValue === "string" && typeof proposedValue === "string") {
150→        // String constraints must match exactly (no ordering)
151→        if (proposedValue !== originalValue) {
152→          violations.push(
153→            `${key}: '${proposedValue}' differs from original '${originalValue}'`,
154→          );
155→        }
156→      }
157→    }
158→  }
159→
160→  // Adding new constraints to proposed (not in original) is tightening -- allowed
161→
162→  return violations.length > 0
163→    ? { valid: false, violations }
164→    : { valid: true };
165→}
