 12→// --- Route Handler Types ---
 13→
 14→type IntentRouteHandlers = {
 15→  handleEvaluate: (intentId: string, request: Request) => Promise<Response>;
 16→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 17→  handleListPending: (workspaceId: string) => Promise<Response>;
 18→  handleConsent: (workspaceId: string, intentId: string) => Promise<Response>;
 19→  handleApprove: (workspaceId: string, intentId: string) => Promise<Response>;
 20→  handleConstrain: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 21→};
