 23→// --- Factory ---
 24→
 25→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 26→  const { surreal } = deps;
 27→
 28→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
 29→
 30→  const handleEvaluate = async (intentId: string, request: Request): Promise<Response> => {
 31→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 32→    let body: IntentRecord | undefined;
 33→    try {
 34→      body = await request.json() as IntentRecord;
 35→    } catch {
 36→      body = undefined;
 37→    }
 38→
 39→    const bodyIntentId = body && typeof body.id === "object" && body.id !== undefined
 40→      ? (body.id.id as string)
 41→      : undefined;
 42→
 43→    if (bodyIntentId && bodyIntentId !== intentId) {
 44→      return jsonError("Intent ID mismatch between path and payload", 400);
 45→    }
 46→
 47→    if (!body) {
 48→      return jsonError("Invalid JSON body", 400);
 49→    }
 50→
 51→    if (!body.requester) {
 52→      return jsonError("Missing requester in intent body", 400);
 53→    }
 54→
 55→    logInfo("intent.evaluate.received", "Evaluate endpoint received intent", {
 56→      intentId,
 57→      status: body.status,
 58→      goal: body.goal,
 59→    });
 60→
 61→    // Idempotency guard: only process intents in pending_auth status
 62→    if (body.status !== "pending_auth") {
 63→      logInfo("intent.evaluate.skipped", "Intent not in pending_auth status", {
 64→        intentId,
 65→        currentStatus: body.status,
 66→      });
 67→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
 68→    }
 69→
 70→    try {
 71→      // Pipeline: policy gate -> LLM evaluator -> risk router -> status update
 72→      const requesterId = typeof body.requester === "object" && body.requester !== undefined
 73→        ? (body.requester.id as string)
 74→        : String(body.requester);
 75→
 76→      const evaluation = await evaluateIntent({
 77→        intent: {
 78→          goal: body.goal,
 79→          reasoning: body.reasoning,
 80→          action_spec: body.action_spec,
 81→          budget_limit: body.budget_limit,
 82→          requester: requesterId,
 83→        },
 84→        policy: {},
 85→        llmEvaluator,
 86→      });
 87→
 88→      const routing = routeByRisk(evaluation);
 89→      const evaluationRecord = {
 90→        ...evaluation,
 91→        evaluated_at: new Date(),
 92→      };
 93→
 94→      switch (routing.route) {
 95→        case "auto_approve": {
 96→          const result = await updateIntentStatus(surreal, intentId, "authorized", {
 97→            evaluation: evaluationRecord,
 98→          });
 99→          if (!result.ok) {
100→            logError(
101→              "intent.evaluate.update_failed",
102→              "Failed to update intent status to authorized",
103→              new Error(result.error),
104→              { intentId },
105→            );
106→            return jsonError(result.error, 409);
107→          }
108→          logInfo("intent.authorized", "Intent auto-approved", { intentId });
109→          return jsonResponse({ intentId, status: "authorized", evaluation }, 200);
110→        }
111→
112→        case "veto_window": {
113→          const result = await updateIntentStatus(surreal, intentId, "pending_veto", {
114→            evaluation: evaluationRecord,
115→            veto_expires_at: routing.expires_at,
116→          });
117→          if (!result.ok) {
118→            logError(
119→              "intent.evaluate.update_failed",
120→              "Failed to update intent status to pending_veto",
121→              new Error(result.error),
122→              { intentId },
123→            );
124→            return jsonError(result.error, 409);
125→          }
126→          logInfo("intent.pending_veto", "Intent requires veto window", {
127→            intentId,
128→            veto_expires_at: routing.expires_at.toISOString(),
129→          });
130→          return jsonResponse({
131→            intentId,
132→            status: "pending_veto",
133→            evaluation,
134→            veto_expires_at: routing.expires_at.toISOString(),
135→          }, 200);
136→        }
137→
138→        case "reject": {
139→          const result = await updateIntentStatus(surreal, intentId, "vetoed", {
140→            evaluation: evaluationRecord,
141→          });
142→          if (!result.ok) {
143→            logError(
144→              "intent.evaluate.update_failed",
145→              "Failed to update intent status to vetoed",
146→              new Error(result.error),
147→              { intentId },
148→            );
149→            return jsonError(result.error, 409);
150→          }
151→          logInfo("intent.vetoed", "Intent rejected by evaluation", {
152→            intentId,
153→            reason: routing.reason,
154→          });
155→          return jsonResponse({ intentId, status: "vetoed", evaluation }, 200);
156→        }
157→      }
158→    } catch (error) {
159→      logError("intent.evaluate.error", "Intent evaluation pipeline failed", error, {
160→        intentId,
161→      });
162→      return jsonError("Internal evaluation error", 500);
163→    }
164→  };
