553→-- In production the server URL is configured via schema migration with the actual port.
554→-- In tests, simulateEvaluation() writes the evaluation result directly, so this event
555→-- firing against an unreachable endpoint is harmless (SurrealDB http::post errors are
556→-- caught and ignored here to prevent blocking the triggering UPDATE).
557→DEFINE EVENT intent_pending_auth ON intent
558→  WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
559→  THEN {};
