  2→ * Audit Event Logging
  3→ *
  4→ * Audit event logging to SurrealDB for security-relevant
  5→ * OAuth operations (token issuance, rejections, DPoP verification,
  6→ * consent actions, intent lifecycle).
  7→ *
  8→ * Pure domain types + SurrealDB adapter.
  9→ *
 10→ * Step: 02-04, 04-04
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types
 16→// ---------------------------------------------------------------------------
 17→
 18→/** All event types matching the schema ASSERT values. */
 19→export type AuditEventType =
 20→  | "intent_submitted"
 21→  | "intent_evaluated"
 22→  | "intent_routed"
 23→  | "consent_approved"
 24→  | "consent_constrained"
 25→  | "consent_vetoed"
 26→  | "token_issued"
 27→  | "token_rejected"
 28→  | "dpop_verified"
 29→  | "dpop_rejected"
 30→  | "security_alert";
 31→
 32→export type AuditSeverity = "info" | "warning" | "security";
 33→
 34→/** Security events that always get elevated severity. */
 35→export const SECURITY_EVENT_TYPES: AuditEventType[] = [
 36→  "dpop_rejected",
 37→  "token_rejected",
 38→  "security_alert",
 39→];
 40→
 41→/** Warning events that indicate operator intervention or constraint. */
 42→const WARNING_EVENT_TYPES: AuditEventType[] = [
 43→  "consent_vetoed",
 44→  "consent_constrained",
 45→];
 46→
 47→/** Classify event severity by event type. */
 48→export function classifySeverity(eventType: AuditEventType): AuditSeverity {
 49→  if (SECURITY_EVENT_TYPES.includes(eventType)) return "security";
 50→  if (WARNING_EVENT_TYPES.includes(eventType)) return "warning";
 51→  return "info";
 52→}
 53→
 54→export type AuditEvent = {
 55→  event_type: AuditEventType;
 56→  severity: AuditSeverity;
 57→  actor: RecordId<"identity", string>;
 58→  workspace: RecordId<"workspace", string>;
 59→  intent_id?: RecordId<"intent", string>;
 60→  dpop_thumbprint?: string;
 61→  payload: Record<string, unknown>;
 62→};
 63→
 64→/** Input for createAuditEvent -- event_type and severity are derived. */
 65→export type AuditEventInput = {
 66→  actor: RecordId<"identity", string>;
 67→  workspace: RecordId<"workspace", string>;
 68→  intent_id?: RecordId<"intent", string>;
 69→  dpop_thumbprint?: string;
 70→  payload: Record<string, unknown>;
 71→};
 72→
 73→/** Build an AuditEvent with auto-classified severity. */
 74→export function createAuditEvent(
 75→  eventType: AuditEventType,
 76→  input: AuditEventInput,
 77→): AuditEvent {
 78→  return {
 79→    event_type: eventType,
 80→    severity: classifySeverity(eventType),
 81→    actor: input.actor,
 82→    workspace: input.workspace,
 83→    ...(input.intent_id ? { intent_id: input.intent_id } : {}),
 84→    ...(input.dpop_thumbprint ? { dpop_thumbprint: input.dpop_thumbprint } : {}),
 85→    payload: input.payload,
 86→  };
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Adapter: SurrealDB
 91→// ---------------------------------------------------------------------------
 92→
 93→export async function logAuditEvent(
 94→  surreal: Surreal,
 95→  event: AuditEvent,
 96→): Promise<void> {
 97→  const id = crypto.randomUUID();
 98→  const record = new RecordId("audit_event", id);
 99→
100→  const content: Record<string, unknown> = {
101→    event_type: event.event_type,
102→    severity: event.severity,
103→    actor: event.actor,
104→    workspace: event.workspace,
105→    payload: event.payload,
106→    created_at: new Date(),
107→  };
108→
109→  if (event.intent_id) {
110→    content.intent_id = event.intent_id;
111→  }
112→  if (event.dpop_thumbprint) {
113→    content.dpop_thumbprint = event.dpop_thumbprint;
114→  }
115→
116→  await surreal.query("CREATE $record CONTENT $content;", {
117→    record,
118→    content,
119→  });
120→}
